fn fetch_with_retry(url: &str) -> Result<String, HttpError> {
    for attempt in 1..=3 {
        match http_get(url) {
            Ok(body) => return Ok(body),
            Err(e) => {
                if attempt == 3 {
                    return Err(e);
                }
            }
        }
    }
    Err(HttpError::Exhausted)
}

