fn normalize(p: &Path) -> std::path::PathBuf {
    let mut out = std::path::PathBuf::new();
    for comp in p.components() {
        match comp {
            std::path::Component::ParentDir => { out.pop(); },
            std::path::Component::CurDir => {},
            other => out.push(other.as_os_str()),
        }
    }
    out
}

