struct TokenBucket {
    tokens: u32,
    capacity: u32,
    refill_per_sec: u32,
}

impl TokenBucket {
    fn new(capacity: u32, refill_per_sec: u32) -> Self {
        Self { tokens: capacity, capacity, refill_per_sec }
    }
    fn try_consume(&mut self) -> bool {
        if self.tokens == 0 {
            return false;
        }
        self.tokens -= 1;
        true
    }
}

