fn aggregate(samples: &[f64]) -> Option<Stats> {
    if samples.is_empty() { return None; }
    let n = samples.len() as f64;
    let mean = samples.iter().sum::<f64>() / n;
    let var = samples.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / n;
    let min = samples.iter().cloned().fold(f64::INFINITY, f64::min);
    let max = samples.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
    Some(Stats { mean, var, min, max })
}

fn merge_k<T: Ord>(mut streams: Vec<BinaryHeap<Reverse<T>>>) -> Vec<T> {
    let mut out = Vec::new();
    while let Some((Reverse(v), idx)) = pick_min(&mut streams) {
        out.push(v);
    }
    out
}

fn pick_min<T: Ord>(streams: &mut [BinaryHeap<Reverse<T>>]) -> Option<(Reverse<T>, usize)> {
    streams.iter_mut().enumerate().filter_map(|(i, h)| h.peek().cloned().map(|v| (v, i))).min_by_key(|&(ref v, _)| v.0.clone())
}

fn encode(s: &str) -> String {
    let mut out = String::with_capacity(s.len() * 3);
    for b in s.bytes() {
        match b {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => out.push(b as char),
            _ => out.push_str(&format!("%{:02X}", b)),
        }
    }
    out
}

