        let raw = std::fs::read_to_string(f).unwrap_or_default();
        for (i, line) in raw.lines().enumerate() {
            if line.len() > 100 { report.add(f.clone(), i + 1, "long line"); }
            if line.contains("TODO") { report.add(f.clone(), i + 1, "todo"); }
            if line.contains("unwrap") { report.add(f.clone(), i + 1, "unwrap"); }
        }
    }
    report
}

